import{_ as e,o as t,c as r,ag as s}from"./chunks/framework.BbyMWZAR.js";const h=JSON.parse('{"title":"Node.js 是什么？为什么单线程还能高并发？","description":"","frontmatter":{"title":"Node.js 是什么？为什么单线程还能高并发？","difficulty":"easy","tags":["Node.js","runtime","event-loop","libuv"],"estimate":10},"headers":[],"relativePath":"domains/nodejs/qa/qa-01-what-is-nodejs.md","filePath":"domains/nodejs/qa/qa-01-what-is-nodejs.md","lastUpdated":1783504823000}'),n={name:"domains/nodejs/qa/qa-01-what-is-nodejs.md"};function d(l,o,a,i,c,g){return t(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="问答-01-入门-node-js-是什么-为什么单线程还能高并发" tabindex="-1">问答 01（入门）：Node.js 是什么？为什么单线程还能高并发？ <a class="header-anchor" href="#问答-01-入门-node-js-是什么-为什么单线程还能高并发" aria-label="Permalink to &quot;问答 01（入门）：Node.js 是什么？为什么单线程还能高并发？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请解释 Node.js 是什么，它的运行时组成是怎样的？它是单线程的，为什么却能支撑高并发的网络服务？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>Node.js 是什么</strong></p><ul><li>Node.js 是一个基于 Chrome V8 引擎的 <strong>JavaScript 运行时（runtime）</strong>，让 JS 能脱离浏览器在服务端运行。</li><li>它并不是一门语言，也不是框架，而是「V8 + libuv + 一批 C++ 绑定 + 核心 JS 库」的组合。</li></ul><p><strong>核心组成</strong></p><ul><li><strong>V8</strong>：把 JS 编译成机器码执行。</li><li><strong>libuv</strong>：提供事件循环（Event Loop）和跨平台异步 I/O（含线程池）。</li><li><strong>C++ Bindings</strong>：把底层能力（文件、网络、加密等）暴露给 JS。</li><li><strong>核心模块</strong>：<code>fs</code>、<code>http</code>、<code>net</code>、<code>stream</code>、<code>crypto</code> 等。</li></ul><p><strong>「单线程」的真正含义</strong></p><ul><li>指的是 <strong>执行 JS 代码的主线程只有一个</strong>（一个 Event Loop）。</li><li>但底层的 I/O 并不是单线程：libuv 有一个默认大小为 4 的线程池（<code>UV_THREADPOOL_SIZE</code>），文件 I/O、DNS、部分 crypto 会走线程池；网络 I/O 则依赖操作系统的 epoll/kqueue/IOCP 事件通知。</li></ul><p><strong>为什么单线程能高并发</strong></p><ul><li>Web 服务大多是 <strong>I/O 密集型</strong>（等数据库、等网络、等磁盘），CPU 大部分时间在「等」。</li><li>传统「一请求一线程」模型下，线程在等待时被阻塞，线程多了后上下文切换和内存开销巨大。</li><li>Node.js 采用 <strong>非阻塞 I/O + 事件驱动</strong>：发起 I/O 后立即返回去处理别的请求，I/O 完成时通过回调/事件通知，主线程几乎不空等，因此少量线程就能扛住大量并发连接。</li></ul><p><strong>局限</strong></p><ul><li><strong>CPU 密集型任务</strong>（图像处理、大量计算、加解密）会阻塞事件循环，导致所有请求变慢。解决方案：<code>worker_threads</code>、<code>cluster</code>、拆分成子进程或独立服务。</li></ul><h2 id="追问-1-node-js-和浏览器里的-js-有什么区别" tabindex="-1">追问 1：Node.js 和浏览器里的 JS 有什么区别？ <a class="header-anchor" href="#追问-1-node-js-和浏览器里的-js-有什么区别" aria-label="Permalink to &quot;追问 1：Node.js 和浏览器里的 JS 有什么区别？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>全局对象</strong>不同：浏览器是 <code>window</code>，Node 是 <code>global</code>（新版本也有 <code>globalThis</code>）。</li><li><strong>API 不同</strong>：浏览器有 DOM/BOM、<code>fetch</code>、<code>localStorage</code>；Node 有 <code>fs</code>、<code>net</code>、<code>process</code>、<code>Buffer</code>、<code>__dirname</code> 等。</li><li><strong>模块系统</strong>：浏览器原生 ESM；Node 历史上是 CommonJS，现同时支持 ESM。</li><li><strong>安全模型</strong>：浏览器有同源策略/沙箱限制；Node 有完整的系统权限（可读写文件、开端口）。</li><li>二者共享 V8 引擎和 ECMAScript 语言标准。</li></ul><h2 id="追问-2-uv-threadpool-size-是干什么的-调大它一定能提升性能吗" tabindex="-1">追问 2：<code>UV_THREADPOOL_SIZE</code> 是干什么的？调大它一定能提升性能吗？ <a class="header-anchor" href="#追问-2-uv-threadpool-size-是干什么的-调大它一定能提升性能吗" aria-label="Permalink to &quot;追问 2：`UV_THREADPOOL_SIZE` 是干什么的？调大它一定能提升性能吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>它设置 libuv 线程池大小（默认 4，最大 1024），影响走线程池的操作：<strong>文件 I/O、DNS 解析（<code>dns.lookup</code>）、<code>crypto.pbkdf2</code>、<code>zlib</code></strong> 等。</li><li>网络 I/O（TCP/HTTP）<strong>不走线程池</strong>，靠 OS 事件机制，因此调大它对纯网络转发无帮助。</li><li>调大是否有效取决于瓶颈：如果是大量并发文件读写或加密，适当调大（贴近 CPU 核数或略高）可提升吞吐；但调太大会增加上下文切换与内存开销，甚至更慢。要结合压测数据设置。</li></ul><h2 id="追问-3-如何判断一个任务是「i-o-密集」还是「cpu-密集」-各自的优化思路是什么" tabindex="-1">追问 3：如何判断一个任务是「I/O 密集」还是「CPU 密集」？各自的优化思路是什么？ <a class="header-anchor" href="#追问-3-如何判断一个任务是「i-o-密集」还是「cpu-密集」-各自的优化思路是什么" aria-label="Permalink to &quot;追问 3：如何判断一个任务是「I/O 密集」还是「CPU 密集」？各自的优化思路是什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>判断</strong>：观察任务大部分时间在「等外部资源」（DB/网络/磁盘）还是在「跑计算」。可用 CPU 使用率、火焰图（<code>--prof</code>、<code>clinic</code>、<code>0x</code>）辅助判断。若单核 CPU 长期接近 100% 且事件循环延迟（<code>perf_hooks</code> monitorEventLoopDelay）高，多半是 CPU 密集。</li><li><strong>I/O 密集优化</strong>：连接池、批量请求、缓存、合理并发控制、使用流避免大内存占用。</li><li><strong>CPU 密集优化</strong>：<code>worker_threads</code> 分担计算、<code>cluster</code> 多进程利用多核、把重计算下沉到原生插件或独立服务、算法优化、必要时用队列削峰。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/en/learn/getting-started/introduction-to-nodejs" target="_blank" rel="noreferrer">Node.js: Introduction to Node.js</a>：单线程、事件驱动模型与运行时组成，答「Node 是什么」的入口。</li><li><a href="https://docs.libuv.org/en/latest/design.html" target="_blank" rel="noreferrer">libuv Design Overview</a>：事件循环与线程池设计，解释为何「单线程」仍能高并发。</li><li><a href="https://nodejs.org/en/docs/" target="_blank" rel="noreferrer">Node.js Docs</a>：官方文档总入口，核对 V8、核心模块与 API 行为。</li></ul>',26)])])}const p=e(n,[["render",d]]);export{h as __pageData,p as default};
